-- Scenario 1: 218 Lakewood Drive, Seneca — Lake Access Cottage with Drive-to-Destination Demand (Lake Hartwell)
-- Category M2-S6-C6 #1 · difficulty 'introductory'
-- ──────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'introductory',
  '218 Lakewood Drive, Seneca — Lake Access Cottage with Drive-to-Destination Demand (Lake Hartwell)',
  'You are appraising the property at 218 Lakewood Drive, Seneca, SC 29678 (2BR/1BA, 980 SF, built 1971, lake access cottage, deeded dock · Lake Hartwell shores). Mortgage lending appraisal of a lake access cottage. The lender wants standard market condition analysis, but the subject''s value is heavily influenced by seasonal and recreational demand. You must address both the permanent residential market indicators and the lake/seasonal demand overlay. Section 6 — Market Analysis — requires you to identify which market indicators and external factors are present in the data package, classify each present indicator as Improving, Stable, Declining, or Market-Dependent based on the indicator data and external context, and write a market-supported rationale citing specific data from the indicator table or external context. Indicators not evidenced in the data package must be left unchecked. Every classification must be grounded in specific evidence — this assignment evaluates evidence-based market analysis, not pattern recognition or reflexive checklist behavior.'
FROM scenario_categories WHERE code = 'M2-S6-C6';

INSERT INTO model_answers
  (scenario_id, field_id, answer_text, field_options_override, model_data)
SELECT
  s.id,
  f.id,
  '',
  '{"subject":{"address_summary":"218 Lakewood Drive, Seneca, SC 29678","subject_summary":"2BR/1BA, 980 SF, built 1971, lake access cottage, deeded dock · Lake Hartwell shores","school":"Oconee County","effective_date":"Current","context_label":"Specialty Situations Context","context_text":"Mortgage lending appraisal of a lake access cottage. The lender wants standard market condition analysis, but the subject''s value is heavily influenced by seasonal and recreational demand. You must address both the permanent residential market indicators and the lake/seasonal demand overlay."},"tables":[{"label":"","cols":["Indicator","Prior 7-12 Months","Current 1-6 Months"],"rows":[["Closed Sales (lake access, Oconee County)","18","24"],["Active Listings","12","7"],["Median Days on Market","44","26"],["Median Sale Price","$312,500","$338,800"],["List-to-Sale Price Ratio","97.4%","100.2%"],["Absorption Rate","5.1 months","2.9 months"]]}],"external":"Post-COVID outdoor recreation and drive-to-destination demand from Charlotte and Atlanta has sustained strong lake property demand. Deeded dock properties at Lake Hartwell command documented premiums over non-dock properties.","factors":[{"id":"abs","label":"Absorption rate trend"},{"id":"dom","label":"Days on market trend"},{"id":"lts","label":"List-to-sale price ratio trend"},{"id":"msp","label":"Median sale price trend"},{"id":"inv","label":"Active listing inventory level"},{"id":"dtd","label":"Drive-to-destination demand driver"},{"id":"dock","label":"Deeded dock premium signal"},{"id":"str","label":"STR gross revenue"},{"id":"sea","label":"Seasonal demand pattern"}],"net_conclusion":"Improving lake access market. All indicators align. Drive-to-destination demand and dock premium both support the Improving designation for the lender''s market condition analysis.","commentary":"Scenario 1 establishes the specialty lake market context. The STR revenue distractor tests whether students introduce data not in the package. The seasonal demand distractor tests whether students cite seasonality without seasonal data support - a common error in lake market appraisals that can create USPAP compliance exposure.","classification_options":["Improving","Stable","Declining","Market-Dependent"],"min_rationale_chars":20}'::jsonb,
  '{"factors":{"abs":{"present":true,"classification":"Improving","rationale":"5.1 to 2.9 months - crossed from balanced into seller''s territory. A strong Improving signal in the lake access market."},"dom":{"present":true,"classification":"Improving","rationale":"44 to 26 days - demand velocity accelerating significantly in the lake access segment."},"lts":{"present":true,"classification":"Improving","rationale":"97.4 to 100.2% - crossed above asking price. Lake access buyers are now bidding at or above list."},"msp":{"present":true,"classification":"Improving","rationale":"+8.4% - meaningful appreciation in the lake access market confirming improving conditions."},"inv":{"present":true,"classification":"Improving","rationale":"12 to 7 actives - tightening supply reinforcing the seller''s market picture."},"dtd":{"present":true,"classification":"Improving","rationale":"Post-COVID drive-to-destination demand from Charlotte and Atlanta is documented, verifiable, and operative as of the current date."},"dock":{"present":true,"classification":"Improving","rationale":"Documented dock premium in the Lake Hartwell market is a real, verifiable indicator of improved demand for dock-access product specifically."},"str":{"present":false,"rationale":"No STR revenue data was provided in this package. Do not introduce indicators not evidenced in the data."},"sea":{"present":false,"rationale":"No seasonal breakdown was provided. Citing seasonality without specific seasonal data support is a common error in lake market appraisals and should be avoided."}}}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'market_indicator_analysis'
WHERE sc.code = 'M2-S6-C6'
  AND s.order_index = 1;


