  s.id,
  f.id,
  '',
  '{"subject":{"address_summary":"Three-Asset Portfolio - Greenville/Oconee County, SC","subject_summary":"Private consulting capstone - full specialty market synthesis for investment committee presentation · Asset 1: Lake Hartwell (Oconee Co.) / Asset 2: Augusta Road (Greenville) / Asset 3: Lowndes Hill (Greenville)","school":"Multiple districts","effective_date":"Current","context_label":"Specialty Situations Context","context_text":"Private consulting capstone. Client is evaluating a three-asset specialty portfolio: (1) a Lake Hartwell STR cottage; (2) an Augusta Road teardown/redevelopment opportunity; (3) a Greenville ADU property. You must identify all present indicators for each asset, classify correctly, and synthesize a differentiated investment committee recommendation."},"tables":[{"label":"ASSET 1 - LAKE HARTWELL STR COTTAGE (OCONEE COUNTY)","cols":["Indicator","Prior 7-12 Months","Current 1-6 Months"],"rows":[["Permanent Market Absorption (lake access)","5.1 months","3.2 months"],["STR Active Listings (Lake Hartwell)","44","61"],["STR Annual Gross Revenue","$38,400","$44,800"],["STR Peak Occupancy","71%","77%"],["STR Regulatory Status","No restriction","Proposed Oconee Co. review"]]},{"label":"ASSET 2 - AUGUSTA ROAD TEARDOWN OPPORTUNITY (GREENVILLE)","cols":["Indicator","Prior 12 Months","Current 12 Months"],"rows":[["General Market Absorption","2.8 months","2.2 months"],["Teardown Sales Frequency","4","8"],["Teardown Premium over Improved Value","19%","28%"],["New Construction Price (finished)","$488,500","$524,800"],["Undeveloped Lots Available (within 5 blocks)","4","2"]]},{"label":"ASSET 3 - LOWNDES HILL ADU PROPERTY (GREENVILLE)","cols":["Indicator","Prior 12 Months","Current 12 Months"],"rows":[["Primary Market Absorption","3.1 months","2.4 months"],["ADU Permit Issuance (Greenville County)","28","44"],["ADU Rental Income (1BR)","$910/mo","$1,040/mo"],["ADU Vacancy Rate","6.8%","4.2%"],["ADU Sales Premium over Non-ADU","11%","18%"]]}],"external":"BMW expansion 2026 supporting Greenville/Spartanburg workforce demand (all three assets benefit from regional strength). Oconee County STR zoning review - 4-month vote timeline (Asset 1 only). Augusta Road corridor city infill initiative ongoing (Asset 2 only). Greenville County ADU by-right zoning in effect (Asset 3 only). Mortgage rates stabilized at approximately 6.5%.","factors":[{"id":"a1_pm","label":"Asset 1: Permanent lake market improving"},{"id":"a1_rev","label":"Asset 1: STR gross revenue improving"},{"id":"a1_occ","label":"Asset 1: STR peak occupancy improving"},{"id":"a1_sup","label":"Asset 1: STR supply growth"},{"id":"a1_reg","label":"Asset 1: STR regulatory risk (Oconee)"},{"id":"a1_seas","label":"Asset 1: Seasonal revenue concentration"},{"id":"a2_abs","label":"Asset 2: General market absorption improving"},{"id":"a2_freq","label":"Asset 2: Teardown sale frequency"},{"id":"a2_prem","label":"Asset 2: Teardown premium expansion"},{"id":"a2_nc","label":"Asset 2: New construction price trend"},{"id":"a2_scar","label":"Asset 2: Lot scarcity acceleration"},{"id":"a2_city","label":"Asset 2: City infill initiative"},{"id":"a3_pm","label":"Asset 3: Primary market improving"},{"id":"a3_per","label":"Asset 3: ADU permit acceleration"},{"id":"a3_rent","label":"Asset 3: ADU rental income trend"},{"id":"a3_vac","label":"Asset 3: ADU vacancy tightening"},{"id":"a3_prem","label":"Asset 3: ADU sales premium growth"},{"id":"a3_reg","label":"Asset 3: ADU by-right zoning"},{"id":"a3_sup","label":"Asset 3: ADU supply growth (future)"},{"id":"cap_d","label":"Cap rate data (any asset)"},{"id":"a2_str","label":"STR risk applied to Asset 2 or Asset 3"},{"id":"sea_23","label":"Seasonal demand for Asset 2 or Asset 3"}],"net_conclusion":"Asset 1 (Lake/STR): Improving headline with STR supply and regulatory risk - proceed with risk-adjusted return expectations. Asset 2 (Teardown): Strongly improving across all indicators - highest conviction opportunity in the portfolio. Asset 3 (ADU): Improving across all indicators with manageable future supply risk. Portfolio recommendation: overweight teardown and ADU; approach lake STR with caution given regulatory exposure.","commentary":"Scenario 10 is the capstone of the entire Section 6 sequence and the PAREA program''s market analysis curriculum. Three specialty assets, multiple market data sets, and a synthesized investment committee narrative. The critical skills: applying the correct indicator set for each specialty type without importing irrelevant factors across assets; recognizing that improving headline metrics carry asset-specific risks; and synthesizing a differentiated portfolio recommendation. Students completing this scenario have demonstrated market analysis competency across all six assignment categories.","classification_options":["Improving","Stable","Declining","Market-Dependent"],"min_rationale_chars":20}'::jsonb,
  '{"factors":{"a1_pm":{"present":true,"classification":"Improving","rationale":"5.1 to 3.2 months absorption - permanent residential lake market improving. Supports the base value thesis for the lake cottage."},"a1_rev":{"present":true,"classification":"Improving","rationale":"$38,400 to $44,800 (+16.7%) - per-property STR revenue growing despite supply expansion. Demand absorbing new supply as of current date."},"a1_occ":{"present":true,"classification":"Improving","rationale":"71 to 77% peak occupancy - strong demand growth in peak season."},"a1_sup":{"present":true,"classification":"Declining","rationale":"44 to 61 listings (+39%) - growing STR competition creates per-property revenue pressure risk going forward."},"a1_reg":{"present":true,"classification":"Declining","rationale":"Active zoning review with 4-month vote timeline is material, imminent, and documented. Asset 1''s income model is exposed."},"a1_seas":{"present":true,"classification":"Market-Dependent","rationale":"STR revenue concentrated in peak season. Investment impact depends on the investor''s financing structure and holding assumptions."},"a2_abs":{"present":true,"classification":"Improving","rationale":"2.8 to 2.2 months - Augusta Road general market tightening further."},"a2_freq":{"present":true,"classification":"Improving","rationale":"4 to 8 transactions - accelerating teardown frequency confirms growing developer/builder demand."},"a2_prem":{"present":true,"classification":"Improving","rationale":"19 to 28% premium - strongest improving signal in the portfolio. Land value materially outpacing improved value."},"a2_nc":{"present":true,"classification":"Improving","rationale":"+7.4% finished new construction prices - expanding the land residual available to support teardown pricing."},"a2_scar":{"present":true,"classification":"Improving","rationale":"4 to 2 undeveloped lots - accelerating scarcity is the strongest long-term premium support for the teardown market."},"a2_city":{"present":true,"classification":"Improving","rationale":"Augusta Road designated as city infill priority - documented public-sector improving signal."},"a3_pm":{"present":true,"classification":"Improving","rationale":"3.1 to 2.4 months - primary market tightening alongside the ADU market."},"a3_per":{"present":true,"classification":"Improving","rationale":"28 to 44 permits (+57%) - growing ADU market adoption supporting rental comparability and lender acceptance."},"a3_rent":{"present":true,"classification":"Improving","rationale":"$910 to $1,040/mo (+14.3%) - strong ADU rent growth confirming tight demand."},"a3_vac":{"present":true,"classification":"Improving","rationale":"6.8 to 4.2% - improving rental vacancy directly supports income reliability."},"a3_prem":{"present":true,"classification":"Improving","rationale":"11 to 18% premium over non-ADU - growing buyer recognition of ADU value."},"a3_reg":{"present":true,"classification":"Improving","rationale":"Permitted by right in all zones - removes regulatory barrier supporting market depth and lender comfort."},"a3_sup":{"present":true,"classification":"Market-Dependent","rationale":"44 new permits represents future ADU supply. Not yet impacting rents but a real forward-looking risk to acknowledge."},"cap_d":{"present":false,"rationale":"No cap rate data was provided for any asset in this package. Do not cite indicators not in the data."},"a2_str":{"present":false,"rationale":"STR regulatory risk applies to Asset 1 only. Do not import Asset 1 risk factors into Assets 2 or 3 where no STR market exists."},"sea_23":{"present":false,"rationale":"No seasonal data was provided for Assets 2 or 3. Seasonality is not relevant to a teardown or ADU residential property."}}}'::jsonb
